args.sparql:
SELECT ?club WHERE {
  wd:Q51 p:P54 ?statement.
  ?statement ps:P54 ?club.
}

SELECT ?club WHERE {
  wd:Q51 p:P463 ?statement.
  ?statement ps:P463 ?club.
}

SELECT ?club WHERE {
  wd:Q17403 p:P463 ?statement.
  ?statement ps:P463 ?club.
  ?statement pq:P580 ?start_date.
  OPTIONAL { ?statement pq:P582 ?end_date. }
  FILTER (SUBSTR(STR(?start_date), 1, 4) <= "1976" && (NOT BOUND(?end_date) || SUBSTR(STR(?end_date), 1, 4) >= "1976"))
}

SELECT DISTINCT ?club WHERE {
  {
    wd:Q51 p:P463 ?statement.
    ?statement ps:P463 ?club.
    ?statement pq:P580 ?start_date.
    ?statement pq:P582 ?end_date.
    FILTER (SUBSTR(STR(?start_date), 1, 4) <= "1976" && SUBSTR(STR(?end_date), 1, 4) >= "1976")
  }
  UNION
  {
    wd:Q51 p:P463 ?statement.
    ?statement ps:P463 ?club.
    ?statement pq:P580 ?start_date.
    FILTER (SUBSTR(STR(?start_date), 1, 4) <= "1976")
  }
}

SELECT ?club ?clubLabel WHERE {
  wd:Q51 p:P2013 ?statement.
  ?statement ps:P2013 ?club.
  ?statement pq:P580 ?start_date.
  ?statement pq:P582 ?end_date.
  FILTER (SUBSTR(STR(?start_date), 1, 4) <= "1976" && SUBSTR(STR(?end_date), 1, 4) >= "1976")
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}
